var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 기록보존실     \\n<color=#ffd34c>제 64 재난지구</color>     \\nCCTV 관련기록 편집 영상 #1","JPN":"管理局の記録保管室     \\n<color=#ffd34c>第64災害地区</color>     \\n監視カメラの関連記録編集映像#1","ENG":"Administration Recordkeeping Room     \\n<color=#ffd34c>64th Disaster District</color>     \\nEdited CCTV Record Video #1","TWN":"管理局 檔案室     \\n<color=#ffd34c>第 64 災難地球</color>     \\nCCTV 相關記錄 編輯影像#1"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"콜록, 콜록......","JPN":"ゲホ、ゲホ……","ENG":"*Cough*, *Cough*","TWN":"咳咳，咳咳……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"벌써 일어났어? 좀 더 쉬라고 했잖아, 엄마.","JPN":"お母さん、もう起きたの？もっと寝ててもいいのに。","ENG":"You're up already? Mom, I told you to rest a bit more.","TWN":"妳已經起來了？我不是說要妳多休息一會了嗎，媽媽。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"일어나야지. 조금 있으면 식량배급표를 나눠 줄 시간이잖니?","JPN":"ううん。もう少しで、食料配給票を配る時間でしょ？","ENG":"I need to get up. They're going to hand out the food stamps soon.","TWN":"我得起來了。不是快要到發糧票的時間了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"그건 내가 알아서 한다니까?","JPN":"私がもらって来るから、気にしなくていいってば。","ENG":"I said I'll take care of that.","TWN":"那不是我去就好了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"몸도 성치 않은 사람이 자꾸 어딜 나가려고 그래?!","JPN":"お母さんは体が弱いから、出かけちゃダメ！","ENG":"Why do you keep trying to go outside when you're sick?","TWN":"身體不好的人，一直想著要出去幹什麼？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"......엄마는 괜찮아. 너야말로 좀 더 자두렴.","JPN":"……お母さんは平気よ。あなたこそもっと寝なさい。","ENG":"I'm fine. You should be the one to get some more sleep.","TWN":"……媽媽沒事。倒是妳再睡會兒吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"구호소 난방도 시원치 않은데 감기 걸리겠다.","JPN":"救護所は暖房が弱いから、風邪をひいちゃうわ。","ENG":"The heating is terrible in the shelter. You'll catch a cold.","TWN":"救護所的暖氣也不太行，你會感冒的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"아, 진짜! 감기는 무슨 감기야! 나 추위 안타는 거 몰라?","JPN":"もう！そんなわけないじゃん！私、寒さに強いの知ってるでしょ？","ENG":"Oh, come on! What cold? Don't you know that I never get cold?","TWN":"啊，真是的！感冒算什麼！妳不知道我不怕冷的嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마도 어렸을 때는 그런 줄 알았단다.","JPN":"お母さんも、若い頃はそう思ってたわ。","ENG":"I thought that too when I was young.","TWN":"媽媽小時候也是這樣認為的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 매년 감기몸살을 달고 살았지.","JPN":"そのせいで、毎年風邪をひいたの。","ENG":"Which is why I always spent every winter with the flu.","TWN":"所以現在每年都會感冒。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"이리 오렴. 목도리 다시 감아 줄 테니까.","JPN":"こっちへ来なさい。マフラーを結び直してあげる。","ENG":"Come here. I'll fix your scarf again.","TWN":"來，我再給妳戴個圍巾。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 다 됐다.","JPN":"はい、できたわよ。","ENG":"Okay, there.","TWN":"好了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 자리 잘 지키고 있어. 엄마는 금방 배급표 받아올게.","JPN":"じゃあ、ここで待っててね。すぐに配給票をもらって来るから。","ENG":"I'll be right back, you stay put. I'm going to go get the food stamps.","TWN":"那妳好好在這裡守著位子。媽媽馬上就拿完糧票了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"엄마. 그러지 말고...... 나랑 같이 관리국에 가면 안돼?","JPN":"お母さん……私と一緒に、管理局に行くのじゃダメ？","ENG":"Mom. Instead of doing that... Can't you just go to the Administration with me?","TWN":"媽媽，別這麼說……妳不能跟我一起去管理局嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"이거 봐! 나도 이젠 카운터라고!","JPN":"ほら！私もカウンターなんだよ！","ENG":"Look! I'm a Counter now!","TWN":"看這個！我已經是制裁者了！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"이 워치만 있으면 배급표 같은 거 안 받아도......","JPN":"このウォッチさえあれば、配給票なんかもらわなくても……","ENG":"We don't need to get food stamps if I just show this Watch...","TWN":"只要有這個能量環，就算不用去拿糧票……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"윤서! 엄마가 그거 꺼내지 말랬지?!","JPN":"シズカ！それは見せちゃダメって言ったでしょ！？","ENG":"Yoon Seo! I told you to keep that hidden!","TWN":"芸徐！媽媽不是告訴過妳，不要把這個拿出來嗎？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 들어, 윤서야. 넌 아직 어려서 잘 모르겠지만......","JPN":"よく聞きなさい、シズカ。あなたはまだ子供だから、わからないでしょうけど……","ENG":"Listen to me, Yoon Seo. You're still too young to understand...","TWN":"聽好了，芸徐。妳還小，有些事妳還不懂……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"특별한 힘이 있다는 게 항상 좋은 일은 아니야.","JPN":"特別な力を持っているのが、必ずしもいいことだとは言えないの。","ENG":"But having special powers isn't always a good thing.","TWN":"但擁有特殊的能力一直都不是件好事。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 걸 가지고 있다는 게 알려지면 오히려 더 위험해질 수도 있어.","JPN":"それを持っているのを周りに知られたら、かえって危険な目に遭うかもしれないわ。","ENG":"If word gets out that you possess something like that, it could put us in danger.","TWN":"如果讓別人知道妳有這個東西，反而會更危險。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"널 이용하려는 나쁜 사람들이 접근할 수도 있고.","JPN":"あなたを利用しようする、悪い人たちが近づいてくるかもしれない。","ENG":"And there will be awful people who will try to use you.","TWN":"還會有很多想要利用妳的壞人接近妳。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그런 게 아니라고 해도, 관리국에서 카운터들에게 시키는 일들은 아주 위험한 것들이야.","JPN":"それだけじゃなくて、管理局がカウンターにやらせる仕事はとても危険なの。","ENG":"And besides, all of the tasks assigned to the Counters by the Administration are very dangerous.","TWN":"而且就算沒碰到這些事情，管理局讓制裁者做的事情都很危險。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체와 싸우면서 크게 다치거나 목숨을 잃을 수도 있다고.","JPN":"侵食体と戦うと、大ケガをしたり命を失ったりするかもしれないわ。","ENG":"You might get hurt or even die while fighting C.O.","TWN":"和侵蝕體的戰鬥中，可能會受到重傷，也可能會喪命。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까 네가 너 스스로를 지킬 힘이 생길 때까지,","JPN":"だから、自分自身を守る力を手に入れるまで、","ENG":"That's why you have to keep that a secret,","TWN":"所以在妳有保護自己的力量之前……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 건 함부로 남에게 알려서는 안 되는 거야. 알겠지?","JPN":"それについては誰にも話しちゃダメよ。わかった？","ENG":"until you're strong enough to keep yourself safe. Do you understand?","TWN":"這種事不可以這樣隨便讓別人知道。明白了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......알았어.","JPN":"……わかった。","ENG":"Okay.","TWN":"……明白了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"미안해. 엄마가 조금 더 강했다면 그런 걱정을 할 필요도 없었을 텐데......","JPN":"ごめんね。母さんがもう少し強かったら、こんな心配をすることもなかったのに……","ENG":"I'm sorry. If I was stronger, you wouldn't even have to worry about that...","TWN":"對不起。如果媽媽再堅強一點，妳就不用擔心這種事了……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"어, 엄마 탓이 아니잖아! 자꾸 나보다 더 바보 같은 소리 할 거야?!","JPN":"お、お母さんのせいじゃないもん！何でそんなこと言うの！？","ENG":"M-Mom, it's not your fault! Are you going to act even more foolish than I am?!","TWN":"這、這不是媽媽的錯呀！不要說傻話！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"콜록! 콜록! ......하하하, 그래 엄마가 바보 같은 소릴 했네. 미안해, 윤서야.","JPN":"ゴホ！ゴホ！……あはは、そうね。バカなことを言ってごめんね、シズカ。","ENG":"*Cough*! *Cough*! Hah hah, yes, I do sound stupid, don't I? I'm sorry, Yoon Seo.","TWN":"咳咳！咳咳！……哈哈哈，是啊，媽媽說了傻話。對不起，芸徐。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까 엄마가 돌아올 때까지 얌전히 있어야 해. 알았지?","JPN":"だから、お母さんが戻って来るまでじっと待ってなさい。わかった？","ENG":"So please just stay put until I come back. Got it?","TWN":"所以在媽媽回來之前要乖乖地待著，知道了吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......알았어.","JPN":"……わかった。","ENG":"Got it.","TWN":"……知道了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 그럼 엄마는 다녀올게.","JPN":"よし。それじゃあお母さん、行ってくるね。","ENG":"Alright then, I'll be right back.","TWN":"好，那媽媽就出門了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};